using System.Data;using System.Text.RegularExpressions;using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Storage;using verii_metivon_api.Core.Persistence;
using verii_metivon_api.Core.Domain;using verii_metivon_api.Modules.Counting.Domain.Entities;using verii_metivon_api.Modules.Parameters.Domain.Entities;
namespace verii_metivon_api.Modules.Counting.Application.Parameters;
public sealed record InventoryCountParametersDto(long?BranchId,long?WarehouseId,bool IsAutomatic,bool AllowManual,string Format,long NextNumber,int IncrementBy,long MinimumNumber,long MaximumNumber,bool DefaultBlindCount,bool FreezeOnCreate,bool AllowPastCountDate,bool RequireStorageLocation,bool IncludeZeroBalances,bool PreventOverlappingOpenCounts,int MaximumLinesPerCount,bool AllowNegativeCountedQuantity,bool RequireReasonCodeForDifference,decimal AutomaticApprovalQuantityTolerance,decimal AutomaticApprovalPercentTolerance,bool AutoApproveWithinTolerance,bool RequireApprovalBeforePosting,bool AllowPostingWithoutDifference,long PostingCurrencyId,string PostingCurrencyCode,string Preview);
public sealed record SaveInventoryCountParametersRequest(long?BranchId,long?WarehouseId,bool IsAutomatic,bool AllowManual,string Format,long NextNumber,int IncrementBy,long MinimumNumber,long MaximumNumber,bool DefaultBlindCount,bool FreezeOnCreate,bool AllowPastCountDate,bool RequireStorageLocation,bool IncludeZeroBalances,bool PreventOverlappingOpenCounts,int MaximumLinesPerCount,bool AllowNegativeCountedQuantity,bool RequireReasonCodeForDifference,decimal AutomaticApprovalQuantityTolerance,decimal AutomaticApprovalPercentTolerance,bool AutoApproveWithinTolerance,bool RequireApprovalBeforePosting,bool AllowPostingWithoutDifference,long PostingCurrencyId);
public interface IInventoryCountParameterService{Task<InventoryCountParametersDto>GetAsync(long?branchId,long?warehouseId,CancellationToken ct);Task<InventoryCountParametersDto>SaveAsync(SaveInventoryCountParametersRequest r,CancellationToken ct);Task<InventoryCountParameterSettings>ResolveSettingsAsync(long?branchId,long?warehouseId,CancellationToken ct);Task<string>ResolveCountNumberAsync(string?requested,long?branchId,CancellationToken ct);}
public sealed class InventoryCountParameterService(MetivonDbContext db):IInventoryCountParameterService
{const string Module="Counting",Reference="InventoryCountNumber",Fallback="CNT-{YYYY}-{NUMBER:6}";static readonly Regex Token=new(@"\{NUMBER(?::(?<length>\d{1,2}))?\}",RegexOptions.Compiled|RegexOptions.IgnoreCase);
public async Task<InventoryCountParametersDto>GetAsync(long?branchId,long?warehouseId,CancellationToken ct){var s=await Sequence(branchId,ct);var p=await ResolveSettingsAsync(branchId,warehouseId,ct);await EnsureCurrency(p,ct);return new(branchId,warehouseId,s.IsAutomatic,s.AllowManual,s.Format,s.CurrentNumber,s.IncrementBy,s.MinimumNumber,s.MaximumNumber,p.DefaultBlindCount,p.FreezeOnCreate,p.AllowPastCountDate,p.RequireStorageLocation,p.IncludeZeroBalances,p.PreventOverlappingOpenCounts,p.MaximumLinesPerCount,p.AllowNegativeCountedQuantity,p.RequireReasonCodeForDifference,p.AutomaticApprovalQuantityTolerance,p.AutomaticApprovalPercentTolerance,p.AutoApproveWithinTolerance,p.RequireApprovalBeforePosting,p.AllowPostingWithoutDifference,p.PostingCurrencyId,p.PostingCurrencyCode,FormatNumber(s.Format,s.CurrentNumber,await BranchCode(branchId,ct)));}
public async Task<InventoryCountParametersDto>SaveAsync(SaveInventoryCountParametersRequest r,CancellationToken ct){Validate(r);await ValidateRefs(r,ct);await using var tx=await db.Database.BeginTransactionAsync(IsolationLevel.Serializable,ct);var s=await db.NumberSequences.FirstOrDefaultAsync(x=>x.Module==Module&&x.Reference==Reference&&x.BranchId==r.BranchId,ct);if(s is null){s=new NumberSequence{Module=Module,Reference=Reference,BranchId=r.BranchId};db.Add(s);}s.Format=r.Format.Trim();s.CurrentNumber=r.NextNumber;s.IncrementBy=r.IncrementBy;s.MinimumNumber=r.MinimumNumber;s.MaximumNumber=r.MaximumNumber;s.IsAutomatic=r.IsAutomatic;s.AllowManual=r.AllowManual;s.IsActive=true;var p=await db.InventoryCountParameterSettings.FirstOrDefaultAsync(x=>x.BranchId==r.BranchId&&x.WarehouseId==r.WarehouseId,ct);if(p is null){p=new InventoryCountParameterSettings{BranchId=r.BranchId,WarehouseId=r.WarehouseId};db.Add(p);}p.DefaultBlindCount=r.DefaultBlindCount;p.FreezeOnCreate=r.FreezeOnCreate;p.AllowPastCountDate=r.AllowPastCountDate;p.RequireStorageLocation=r.RequireStorageLocation;p.IncludeZeroBalances=r.IncludeZeroBalances;p.PreventOverlappingOpenCounts=r.PreventOverlappingOpenCounts;p.MaximumLinesPerCount=r.MaximumLinesPerCount;p.AllowNegativeCountedQuantity=r.AllowNegativeCountedQuantity;p.RequireReasonCodeForDifference=r.RequireReasonCodeForDifference;p.AutomaticApprovalQuantityTolerance=r.AutomaticApprovalQuantityTolerance;p.AutomaticApprovalPercentTolerance=r.AutomaticApprovalPercentTolerance;p.AutoApproveWithinTolerance=r.AutoApproveWithinTolerance;p.RequireApprovalBeforePosting=r.RequireApprovalBeforePosting;p.AllowPostingWithoutDifference=r.AllowPostingWithoutDifference;var currency=await Currency(r.PostingCurrencyId,ct);p.PostingCurrencyId=currency.Id;p.PostingCurrencyCode=currency.IsoCode;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return await GetAsync(r.BranchId,r.WarehouseId,ct);}
public async Task<InventoryCountParameterSettings>ResolveSettingsAsync(long?branchId,long?warehouseId,CancellationToken ct)=>await db.InventoryCountParameterSettings.AsNoTracking().Where(x=>(x.BranchId==branchId||x.BranchId==null)&&(x.WarehouseId==warehouseId||x.WarehouseId==null)).OrderByDescending(x=>x.WarehouseId.HasValue).ThenByDescending(x=>x.BranchId.HasValue).FirstOrDefaultAsync(ct)??new InventoryCountParameterSettings{BranchId=branchId,WarehouseId=warehouseId};
public async Task<string>ResolveCountNumberAsync(string?requested,long?branchId,CancellationToken ct){var s=await Sequence(branchId,ct);var manual=requested?.Trim().ToUpperInvariant();if(!string.IsNullOrWhiteSpace(manual)){if(s.IsAutomatic&&!s.AllowManual)throw new InvalidOperationException("Manual count number is disabled by counting parameters.");return manual;}if(!s.IsAutomatic)throw new InvalidOperationException("Count number is required because automatic numbering is disabled.");return FormatNumber(s.Format,await Consume(s,ct),await BranchCode(branchId,ct));}
async Task<NumberSequence>Sequence(long?branchId,CancellationToken ct)=>await db.NumberSequences.AsNoTracking().Where(x=>x.Module==Module&&x.Reference==Reference&&x.IsActive&&(x.BranchId==branchId||x.BranchId==null)).OrderByDescending(x=>x.BranchId.HasValue).FirstOrDefaultAsync(ct)??new NumberSequence{Module=Module,Reference=Reference,BranchId=branchId,Format=Fallback,CurrentNumber=1,IncrementBy=1,MinimumNumber=1,MaximumNumber=999999999,IsAutomatic=true,AllowManual=true};
async Task EnsureCurrency(InventoryCountParameterSettings p,CancellationToken ct){if(p.PostingCurrencyId>0)return;var id=await db.Currencies.AsNoTracking().Where(x=>x.IsActive).OrderByDescending(x=>x.IsDefault).ThenBy(x=>x.Id).Select(x=>x.Id).FirstOrDefaultAsync(ct);var currency=await Currency(id,ct);p.PostingCurrencyId=currency.Id;p.PostingCurrencyCode=currency.IsoCode;}
async Task<Currency>Currency(long id,CancellationToken ct)=>await db.Currencies.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==id&&x.IsActive,ct)??throw new ArgumentException("Selected currency is not active.");
async Task ValidateRefs(SaveInventoryCountParametersRequest r,CancellationToken ct){if(r.BranchId.HasValue&&!await db.Branches.AnyAsync(x=>x.Id==r.BranchId&&x.IsActive,ct))throw new ArgumentException("Selected branch is not active.");if(r.WarehouseId.HasValue&&!await db.Warehouses.AnyAsync(x=>x.Id==r.WarehouseId&&x.IsActive&&(!r.BranchId.HasValue||x.BranchId==r.BranchId),ct))throw new ArgumentException("Selected warehouse is not active or does not belong to the selected branch.");}
static void Validate(SaveInventoryCountParametersRequest r){if(!Token.IsMatch(r.Format)||r.Format.Length>120||FormatNumber(r.Format,r.NextNumber,"0").Length>40)throw new ArgumentException("Count mask is invalid or generates more than 40 characters.");if(r.IncrementBy<1||r.MinimumNumber<0||r.NextNumber<r.MinimumNumber||r.MaximumNumber<r.NextNumber)throw new ArgumentException("Document number range is invalid.");if(r.MaximumLinesPerCount is <1 or >100000)throw new ArgumentException("Maximum count line count is invalid.");if(r.AutomaticApprovalQuantityTolerance<0||r.AutomaticApprovalPercentTolerance is <0 or >100)throw new ArgumentException("Count tolerance is invalid.");if(r.PostingCurrencyId<=0)throw new ArgumentException("A defined posting currency is required.");}
async Task<string>BranchCode(long?id,CancellationToken ct)=>id.HasValue?await db.Branches.AsNoTracking().Where(x=>x.Id==id).Select(x=>x.Code).FirstOrDefaultAsync(ct)??"0":"0";async Task<long>Consume(NumberSequence s,CancellationToken ct){var stored=await db.NumberSequences.FirstOrDefaultAsync(x=>x.Module==Module&&x.Reference==Reference&&x.BranchId==s.BranchId,ct);if(stored is null){stored=new NumberSequence{Module=Module,Reference=Reference,BranchId=s.BranchId,Format=s.Format,CurrentNumber=s.CurrentNumber,IncrementBy=s.IncrementBy,MinimumNumber=s.MinimumNumber,MaximumNumber=s.MaximumNumber,IsAutomatic=s.IsAutomatic,AllowManual=s.AllowManual,IsActive=true};db.Add(stored);await db.SaveChangesAsync(ct);}var c=db.Database.GetDbConnection();if(c.State!=ConnectionState.Open)await c.OpenAsync(ct);await using var cmd=c.CreateCommand();cmd.Transaction=db.Database.CurrentTransaction?.GetDbTransaction();cmd.CommandText="UPDATE RII_NUMBER_SEQUENCES WITH (UPDLOCK, ROWLOCK) SET CurrentNumber=CurrentNumber+IncrementBy,UpdatedAt=SYSUTCDATETIME() OUTPUT DELETED.CurrentNumber WHERE Id=@id AND IsActive=1 AND CurrentNumber<=MaximumNumber";var q=cmd.CreateParameter();q.ParameterName="@id";q.Value=stored.Id;cmd.Parameters.Add(q);var value=await cmd.ExecuteScalarAsync(ct);return value is null||value==DBNull.Value?throw new InvalidOperationException("Count number sequence could not be consumed."):Convert.ToInt64(value);}static string FormatNumber(string f,long n,string branch){var result=f.Replace("{BRANCH}",branch,StringComparison.OrdinalIgnoreCase).Replace("{YYYY}",DateTime.UtcNow.ToString("yyyy"),StringComparison.OrdinalIgnoreCase).Replace("{YY}",DateTime.UtcNow.ToString("yy"),StringComparison.OrdinalIgnoreCase).Replace("{MM}",DateTime.UtcNow.ToString("MM"),StringComparison.OrdinalIgnoreCase);return Token.Replace(result,m=>n.ToString().PadLeft(Math.Clamp(int.TryParse(m.Groups["length"].Value,out var l)?l:1,1,18),'0'));}}
